 namespace WPAICG\Shortcodes; use WPAICG\Shortcodes\TokenUsage\Render as TokenUsageRenderer; use WPAICG\Shortcodes\TokenUsage\Helpers as TokenUsageHelpers; $base_path = __DIR__ . '/token-usage/'; require_once $base_path . 'render/methods.php'; require_once $base_path . 'helpers/get_user_limit_for_module.php'; require_once $base_path . 'data/get_user_token_usage_data.php'; require_once $base_path . 'data/get_user_purchase_history.php'; if (!defined('ABSPATH')) { exit; } class AIPKit_Token_Usage_Shortcode { public function init_hooks() { add_action('wp_ajax_aipkit_get_token_usage_details', [$this, 'ajax_get_token_usage_details']); } public function ajax_get_token_usage_details() { check_ajax_referer('aipkit_token_usage_details_nonce', 'nonce'); if (!is_user_logged_in()) { wp_send_json_error(['message' => __('You must be logged in to view details.', 'gpt3-ai-content-generator')], 403); return; } $user_id = get_current_user_id(); $module = isset($_POST['module']) ? sanitize_key($_POST['module']) : ''; $context_id = isset($_POST['context_id']) ? absint($_POST['context_id']) : 0; $page = isset($_POST['page']) ? absint($_POST['page']) : 1; $per_page = 10; if (empty($module)) { wp_send_json_error(['message' => __('Module not specified.', 'gpt3-ai-content-generator')], 400); return; } global $wpdb; $table_name = $wpdb->prefix . 'aipkit_chat_logs'; $where_clauses = ['user_id = %d', 'module = %s']; $params = [$user_id, $module]; if ($module === 'chat') { if (empty($context_id)) { wp_send_json_error(['message' => __('Chatbot ID is required.', 'gpt3-ai-content-generator')], 400); return; } $where_clauses[] = 'bot_id = %d'; $params[] = $context_id; } else { $where_clauses[] = 'bot_id IS NULL'; } $where_sql = implode(' AND ', $where_clauses); $cache_key = 'aipkit_token_usage_details_' . md5(serialize($params)); $cache_group = 'aipkit_token_usage'; $conversations = wp_cache_get($cache_key, $cache_group); if (false === $conversations) { $conversations = $wpdb->get_results($wpdb->pre